/**
 * Immutable LIFO stack.
 */
export class Stack {
  /** @type {unknown[]} */
  #items;

  /** @param {unknown[]} [items] */
  constructor(items = []) {
    this.#items = [...items];
  }

  /** @param {unknown} value */
  push(value) {
    return new Stack([...this.#items, value]);
  }

  /**
   * @returns {{ value: unknown, stack: Stack }}
   */
  pop() {
    if (this.#items.length === 0) {
      throw new Error('stack is empty');
    }
    const value = this.#items[this.#items.length - 1];
    const stack = new Stack(this.#items.slice(0, -1));
    return { value, stack };
  }

  /** @returns {unknown} */
  peek() {
    if (this.#items.length === 0) {
      throw new Error('stack is empty');
    }
    return this.#items[this.#items.length - 1];
  }

  /** @returns {number} */
  size() {
    return this.#items.length;
  }
}
